/**
 * Priority-based notification router.
 *
 * This replaces the previous broadcast approach where all channel handlers
 * independently subscribed to every EventBus event. The new requirement is
 * priority-based routing:
 *
 *   urgent  → SMS channel
 *   normal  → email channel
 *   low     → webhook channel
 *
 * The router accepts a notification with a priority field and delegates to
 * exactly one channel handler based on that priority.
 *
 * Depends on:
 * - NotificationService (email channel)
 * - SmsChannelService (SMS channel)
 * - WebhookChannelService (webhook channel)
 */

import type { NotificationService } from './notification.service.js';
import type { SmsChannelService } from './sms-channel.service.js';
import type { WebhookChannelService } from './webhook-channel.service.js';
import { Logger } from '../utils/logger.js';

export type NotificationPriority = 'urgent' | 'normal' | 'low';

export interface PriorityNotification {
  priority: NotificationPriority;
  recipient: string;
  subject: string;
  body: string;
  phoneNumber?: string;
  webhookUrl?: string;
  webhookEventType?: string;
  metadata?: Record<string, unknown>;
}

export interface RouteResult {
  channel: 'sms' | 'email' | 'webhook';
  priority: NotificationPriority;
  success: boolean;
}

export class PriorityRouter {
  private logger = new Logger('PriorityRouter');

  constructor(
    private emailChannel: NotificationService,
    private smsChannel: SmsChannelService,
    private webhookChannel: WebhookChannelService,
  ) {}

  /**
   * Route a notification to the appropriate channel based on priority.
   *
   *   urgent  → SMS
   *   normal  → email
   *   low     → webhook
   */
  route(notification: PriorityNotification): RouteResult {
    this.logger.info(
      `Routing ${notification.priority} notification to ${this.channelForPriority(notification.priority)}`,
    );

    switch (notification.priority) {
      case 'urgent':
        return this.routeToSms(notification);
      case 'normal':
        return this.routeToEmail(notification);
      case 'low':
        return this.routeToWebhook(notification);
      default: {
        const _exhaustive: never = notification.priority;
        throw new Error(`Unknown priority: ${_exhaustive}`);
      }
    }
  }

  /**
   * Get the channel name for a given priority.
   */
  channelForPriority(priority: NotificationPriority): 'sms' | 'email' | 'webhook' {
    switch (priority) {
      case 'urgent':
        return 'sms';
      case 'normal':
        return 'email';
      case 'low':
        return 'webhook';
    }
  }

  private routeToSms(notification: PriorityNotification): RouteResult {
    const phoneNumber = notification.phoneNumber ?? this.derivePhoneNumber(notification.recipient);
    this.smsChannel.send({
      phoneNumber,
      body: `[URGENT] ${notification.subject}: ${notification.body}`,
    });
    return { channel: 'sms', priority: 'urgent', success: true };
  }

  private routeToEmail(notification: PriorityNotification): RouteResult {
    this.emailChannel.send({
      recipient: notification.recipient,
      subject: notification.subject,
      body: notification.body,
    });
    return { channel: 'email', priority: 'normal', success: true };
  }

  private routeToWebhook(notification: PriorityNotification): RouteResult {
    const url = notification.webhookUrl ?? 'https://hooks.default/notifications';
    const eventType = notification.webhookEventType ?? 'notification';
    this.webhookChannel.send({
      url,
      eventType,
      payload: {
        subject: notification.subject,
        body: notification.body,
        recipient: notification.recipient,
        priority: notification.priority,
        ...notification.metadata,
      },
    });
    return { channel: 'webhook', priority: 'low', success: true };
  }

  /**
   * Fallback phone number derivation from recipient identifier.
   */
  private derivePhoneNumber(recipient: string): string {
    return `+1-555-${recipient.replace(/\D/g, '').padStart(4, '0').slice(-4)}`;
  }
}

