/**
 * Handle order created event — send confirmation to user.
 * When a priority router is configured, delegates routing based on priority.
 */
private handleOrderCreated(event: OrderCreatedEvent): void {
  this.logger.info(`Sending order confirmation for order ${event.order.id}`);

  const itemSummary = event.order.items
    .map((item) => `${item.name} x${item.quantity}`)
    .join(', ');

  const subject = `Order Confirmation: ${event.order.id}`;
  const body = `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`;

  if (this.priorityRouter) {
    const priority = this.determinePriority(event.order.total);
    this.priorityRouter.route({
      priority,
      recipient: event.user.email,
      subject,
      body,
    });
  } else {
    this.sendNotification({ recipient: event.user.email, subject, body });
  }
}

/**
 * Handle order status change — notify user of update.
 * When a priority router is configured, delegates routing based on priority.
 */
private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
  this.logger.info(
    `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
  );

  const subject = `Order Update: ${event.order.id}`;
  const body = `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`;

  if (this.priorityRouter) {
    const priority = this.determineStatusChangePriority(event.newStatus);
    this.priorityRouter.route({
      priority,
      recipient: event.order.userId,
      subject,
      body,
    });
  } else {
    this.sendNotification({ recipient: event.order.userId, subject, body });
  }
}

/**
 * Determine notification priority based on order total.
 * High-value orders are urgent, mid-range are normal, low-value are low priority.
 */
private determinePriority(orderTotal: number): NotificationPriority {
  if (orderTotal >= 100) return 'urgent';
  if (orderTotal >= 25) return 'normal';
  return 'low';
}

/**
 * Determine notification priority based on status change.
 * Cancellations are urgent, shipping is normal, other updates are low priority.
 */
private determineStatusChangePriority(newStatus: string): NotificationPriority {
  if (newStatus === 'cancelled') return 'urgent';
  if (newStatus === 'shipped' || newStatus === 'delivered') return 'normal';
  return 'low';
}

