import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import {
  SmsChannelService,
  resetSmsIdCounter,
} from '../../src/services/sms-channel.service.js';
import {
  WebhookChannelService,
  resetWebhookDeliveryIdCounter,
} from '../../src/services/webhook-channel.service.js';
import { PriorityRouter } from '../../src/services/priority-router.js';
import type { PriorityNotification } from '../../src/services/priority-router.js';
import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('PriorityRouter', () => {
  let eventBus: EventBus;
  let emailChannel: NotificationService;
  let smsChannel: SmsChannelService;
  let webhookChannel: WebhookChannelService;
  let router: PriorityRouter;

  beforeEach(() => {
    eventBus = new EventBus();
    statusChangeCallbacks.clear();
    emailChannel = new NotificationService(eventBus);
    smsChannel = new SmsChannelService(eventBus);
    webhookChannel = new WebhookChannelService(eventBus);
    router = new PriorityRouter(emailChannel, smsChannel, webhookChannel);
    resetNotificationIdCounter();
    resetSmsIdCounter();
    resetWebhookDeliveryIdCounter();
  });

  describe('priority routing', () => {
    it('should route urgent notifications to SMS channel', () => {
      const notification: PriorityNotification = {
        priority: 'urgent',
        recipient: 'user-1',
        subject: 'Urgent Alert',
        body: 'Your order has been cancelled.',
        phoneNumber: '+1-555-1234',
      };

      const result = router.route(notification);

      expect(result.channel).toBe('sms');
      expect(result.priority).toBe('urgent');
      expect(result.success).toBe(true);
      expect(smsChannel.getMessageCount()).toBe(1);
      expect(smsChannel.getMessages()[0]?.body).toContain('[URGENT]');
      expect(smsChannel.getMessages()[0]?.phoneNumber).toBe('+1-555-1234');
      // Email and webhook should NOT have received anything via router
      expect(emailChannel.getNotificationCount()).toBe(0);
      expect(webhookChannel.getDeliveryCount()).toBe(0);
    });

    it('should route normal notifications to email channel', () => {
      const notification: PriorityNotification = {
        priority: 'normal',
        recipient: 'alice@example.com',
        subject: 'Order Shipped',
        body: 'Your order has shipped.',
      };

      const result = router.route(notification);

      expect(result.channel).toBe('email');
      expect(result.priority).toBe('normal');
      expect(result.success).toBe(true);
      expect(emailChannel.getNotificationCount()).toBe(1);
      expect(emailChannel.getNotifications()[0]?.recipient).toBe('alice@example.com');
      expect(emailChannel.getNotifications()[0]?.subject).toBe('Order Shipped');
      // SMS and webhook should NOT have received anything via router
      expect(smsChannel.getMessageCount()).toBe(0);
      expect(webhookChannel.getDeliveryCount()).toBe(0);
    });

    it('should route low-priority notifications to webhook channel', () => {
      const notification: PriorityNotification = {
        priority: 'low',
        recipient: 'user-1',
        subject: 'Order Confirmed',
        body: 'Your order status has changed.',
        webhookUrl: 'https://hooks.example.com/orders',
        webhookEventType: 'order.updated',
      };

      const result = router.route(notification);

      expect(result.channel).toBe('webhook');
      expect(result.priority).toBe('low');
      expect(result.success).toBe(true);
      expect(webhookChannel.getDeliveryCount()).toBe(1);
      const delivery = webhookChannel.getDeliveries()[0]!;
      expect(delivery.url).toBe('https://hooks.example.com/orders');
      expect(delivery.eventType).toBe('order.updated');
      expect(delivery.payload).toMatchObject({
        subject: 'Order Confirmed',
        body: 'Your order status has changed.',
        recipient: 'user-1',
        priority: 'low',
      });
      // Email and SMS should NOT have received anything via router
      expect(emailChannel.getNotificationCount()).toBe(0);
      expect(smsChannel.getMessageCount()).toBe(0);
    });
  });

  describe('channelForPriority', () => {
    it('should map urgent to sms', () => {
      expect(router.channelForPriority('urgent')).toBe('sms');
    });

    it('should map normal to email', () => {
      expect(router.channelForPriority('normal')).toBe('email');
    });

    it('should map low to webhook', () => {
      expect(router.channelForPriority('low')).toBe('webhook');
    });
  });

  describe('default values', () => {
    it('should derive phone number from recipient when not provided', () => {
      const notification: PriorityNotification = {
        priority: 'urgent',
        recipient: 'user-1234',
        subject: 'Alert',
        body: 'Test',
      };

      router.route(notification);

      expect(smsChannel.getMessages()[0]?.phoneNumber).toBe('+1-555-1234');
    });

    it('should use default webhook URL when not provided', () => {
      const notification: PriorityNotification = {
        priority: 'low',
        recipient: 'user-1',
        subject: 'Info',
        body: 'Test',
      };

      router.route(notification);

      expect(webhookChannel.getDeliveries()[0]?.url).toBe('https://hooks.default/notifications');
    });

    it('should use default webhook event type when not provided', () => {
      const notification: PriorityNotification = {
        priority: 'low',
        recipient: 'user-1',
        subject: 'Info',
        body: 'Test',
      };

      router.route(notification);

      expect(webhookChannel.getDeliveries()[0]?.eventType).toBe('notification');
    });
  });

  describe('webhook metadata', () => {
    it('should include metadata in webhook payload', () => {
      const notification: PriorityNotification = {
        priority: 'low',
        recipient: 'user-1',
        subject: 'Info',
        body: 'Test',
        metadata: { orderId: 'order-42', source: 'system' },
      };

      router.route(notification);

      const payload = webhookChannel.getDeliveries()[0]?.payload;
      expect(payload).toMatchObject({
        orderId: 'order-42',
        source: 'system',
      });
    });
  });

  describe('integration with NotificationService priority routing', () => {
    it('should route high-value order creation to SMS (urgent)', async () => {
      emailChannel.setPriorityRouter(router);

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Expensive Widget', quantity: 1, unitPrice: 150 }],
          total: 150,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // Urgent (total >= 100) → SMS
      expect(smsChannel.getMessageCount()).toBeGreaterThanOrEqual(1);
      const smsMessages = smsChannel.getMessages();
      const routedMsg = smsMessages.find((m) => m.body.includes('[URGENT]'));
      expect(routedMsg).toBeDefined();
      expect(routedMsg!.body).toContain('Order Confirmation');
    });

    it('should route mid-value order creation to email (normal)', async () => {
      emailChannel.setPriorityRouter(router);

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-2',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 50 }],
          total: 50,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // Normal (25 <= total < 100) → email
      const emailNotifications = emailChannel.getNotifications();
      const routedNotif = emailNotifications.find((n) => n.subject.includes('Order Confirmation'));
      expect(routedNotif).toBeDefined();
      expect(routedNotif!.recipient).toBe('alice@example.com');
    });

    it('should route low-value order creation to webhook (low)', async () => {
      emailChannel.setPriorityRouter(router);

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-3',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Sticker', quantity: 1, unitPrice: 5 }],
          total: 5,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // Low (total < 25) → webhook
      expect(webhookChannel.getDeliveryCount()).toBeGreaterThanOrEqual(1);
    });

    it('should route cancellation status change to SMS (urgent)', () => {
      emailChannel.setPriorityRouter(router);

      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'cancelled',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'cancelled',
        timestamp: new Date(),
      };

      statusChangeCallbacks.notify(event);

      // Cancelled → urgent → SMS
      const smsMessages = smsChannel.getMessages();
      const routedMsg = smsMessages.find((m) => m.body.includes('[URGENT]'));
      expect(routedMsg).toBeDefined();
      expect(routedMsg!.body).toContain('Order Update');
    });

    it('should route shipped status change to email (normal)', () => {
      emailChannel.setPriorityRouter(router);

      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      };

      statusChangeCallbacks.notify(event);

      // Shipped → normal → email
      const emailNotifications = emailChannel.getNotifications();
      const routedNotif = emailNotifications.find((n) => n.subject.includes('Order Update'));
      expect(routedNotif).toBeDefined();
    });

    it('should route confirmed status change to webhook (low)', () => {
      emailChannel.setPriorityRouter(router);

      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      statusChangeCallbacks.notify(event);

      // Confirmed → low → webhook
      expect(webhookChannel.getDeliveryCount()).toBeGreaterThanOrEqual(1);
    });
  });
});

